STRINGS_TO_SANITIZE = ["\x00"]


def sanitize_strings(v: str) -> str:
    for string in STRINGS_TO_SANITIZE:
        v = v.replace(string, "")
    return v



# https://docs.pydantic.dev/latest/concepts/validators/#annotated-validators
